	//----------------------------------------------------------------------------------------------------------
	public void onCalculate() throws Exception
	{
		try
		{
			if(!Sys.atSteadyState() || !isRunning())
			{
				logger.trace("\t" + getSlotPath()	+ "\t'onCalculate()' method  --  'if(!Sys.atSteadyState() || !isRunning())' == true.");
				return;
			}
			
			while (((BObject)get("In_"+count))!=null && !ValFlag1)
			{
				InVal = ((BStatusBoolean) ((BObject)get("In_"+count)));                        

				/** Tests whether the slot is linked. If not, the value is set to null **/
				if (getProgram().getLinks(getProperty("In_"+count)).length == 0)
				{
					InVal.setStatusNull(true); 
				}

				/** Tests whether the slot is true and valid **/
				if (InVal.getValue() && InVal.getStatus().isValid())
				{ 
					ValFlag1 = true;
				}

				count++;
			}

			/** Turns Output On **/
			if (ValFlag1)
			{
				if(getToNull()) 
				{
					// setOutRev(new BStatusBoolean(false, BStatus.nullStatus));
					getOutRev().setValue(false);
					if( getOutRev().getStatus()!=BStatus.nullStatus ){ getOutRev().setStatus(BStatus.nullStatus); }
				}
				else
				{
					// setOutRev(new BStatusBoolean(false, BStatus.ok));
					getOutRev().setValue(false);
					if( getOutRev().getStatus()!=BStatus.ok ){ getOutRev().setStatus(BStatus.ok); }
				}
				
				// setOut(new BStatusBoolean(true, BStatus.ok));
				getOut().setValue(true);
				if( getOut().getStatus()!=BStatus.ok ){ getOut().setStatus(BStatus.ok); }
				
				if(getWhenToFireTopics().getOrdinal()==0)
				{
					fireTrue(BBoolean.make(true));
				}
				
				ValFlag1=false;      
			}
			/** Turns Output Off **/
			else
			{
				if(!getToNull())
				{
					// setOutRev(new BStatusBoolean(true, BStatus.ok));
					// setOut(new BStatusBoolean(false, BStatus.ok));
					
					getOutRev().setValue(true);
					if( getOutRev().getStatus()!=BStatus.ok ){ getOutRev().setStatus(BStatus.ok); }
					
					getOut().setValue(false);
					if( getOut().getStatus()!=BStatus.ok ){ getOut().setStatus(BStatus.ok); }
				}
				else 
				{
					// setOutRev(new BStatusBoolean(true, BStatus.nullStatus));
					// setOut(new BStatusBoolean(false, BStatus.nullStatus));
					
					getOutRev().setValue(true);
					if( getOutRev().getStatus()!=BStatus.nullStatus ){ getOutRev().setStatus(BStatus.nullStatus); }
					
					getOut().setValue(false);
					if( getOut().getStatus()!=BStatus.nullStatus ){ getOut().setStatus(BStatus.nullStatus); }
				}
				
				if(getWhenToFireTopics().getOrdinal()==0)
				{
					fireFalse(BBoolean.make(true));
				}
			}

			ValFlag1	= false;  
			count		= 1;
		}
		catch (Exception e) 
		{
			logger.error("\t" + getSlotPath()	+ "\n'onCalculate()' method had an error.\n" + e.getMessage() + "\n" + e.getStackTrace());
		}
	}
	
	

	
	//----------------------------------------------------------------------------------------------------------
	void updateTimer()
	{
		if (ticket != null)ticket.cancel();
		// ticket = Clock.schedule(getProgram(), BRelTime.makeSeconds(1), BSuperOr.calculate, null);
		
		if(getTime().getMillis()>0)
		{
		  ticket = Clock.schedule(getProgram(), getTime(), BSuperOr.calculate, null);
		}
		else
		{
		  calculate();
		}
	}

	Clock.Ticket ticket;      /** Used to manage the current timer **/

	//----------------------------------------------------------------------------------------------------------
	public void slots(double MD) throws Exception
	{
		for(int i=1; i<(MD+1 ); i++)
		{
			if(((BObject)get("In_"+i))==null) {getProgram().add(("In_"+i), new BStatusBoolean(false), Flags.SUMMARY | Flags.EXECUTE_ON_CHANGE);}
		}

		for(int i=(int)MD+1;((BObject)get("In_"+i))!=null;i++)
		{
			if(((BObject)get("In_"+i))!=null) {getProgram().remove("In_"+i);}             
		}
	}


